import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import "./studentDashboard.css";

const StudentDashboard = () => {
  const navigate = useNavigate();

  const token = localStorage.getItem("token");
  const userId = localStorage.getItem("userId");
  const role = localStorage.getItem("role");

  const [tab, setTab] = useState("overview");
  const [profile, setProfile] = useState({ studentname: "Loading..." });
  const [mentors, setMentors] = useState([]);
  const [meetings, setMeetings] = useState([]);
  const [reports, setReports] = useState([]);
  const [requests, setRequests] = useState([]);
  const [error, setError] = useState("");

  // Project Modal
  const [showProjectModal, setShowProjectModal] = useState(false);
  const [selectedMentor, setSelectedMentor] = useState("");
  const [projTitle, setProjTitle] = useState("");
  const [projDomain, setProjDomain] = useState("");
  const [projDesc, setProjDesc] = useState("");
  const [reportFile, setReportFile] = useState(null);

  /* ---------- API ---------- */
  const api = async (path, opts = {}) => {
    const res = await fetch(`http://localhost:5050${path}`, {
      ...opts,
      headers: { Authorization: `Bearer ${token}`, ...opts.headers },
    });
    const data = await res.json();
    return { ok: res.ok, data };
  };

  const loadAll = async () => {
    const [p, m, meet, rep, req] = await Promise.all([
      api("/api/students/me"),
      api("/api/students/mentors"),
      api(`/api/students/meetings/${userId}`),
      api(`/api/students/reports/${userId}`),
      api(`/api/students/requests/${userId}`),
    ]);
    if (p.ok) setProfile(p.data);
    if (m.ok) setMentors(m.data);
    if (meet.ok) setMeetings(meet.data);
    if (rep.ok) setReports(rep.data);
    if (req.ok) setRequests(req.data);
  };

  useEffect(() => {
    if (!token || role !== "student") {
      navigate("/login");
      return;
    }
    loadAll();
  }, [token, role, navigate, userId]);

  const handleLogout = () => {
    localStorage.clear();
    navigate("/login");
  };

  const openProjectModal = (mentorId) => {
    setSelectedMentor(mentorId);
    setShowProjectModal(true);
  };

  const submitProject = async (e) => {
    e.preventDefault();
    const payload = { mentor_id: selectedMentor, title: projTitle, domain: projDomain, description: projDesc };
    const { ok, data } = await api("/api/students/request", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload),
    });
    if (ok) {
      setShowProjectModal(false);
      setProjTitle(""); setProjDomain(""); setProjDesc("");
      loadAll();
    } else setError(data.error);
  };

  const uploadReport = async (e) => {
    e.preventDefault();
    if (!reportFile) return;
    const form = new FormData();
    form.append("report", reportFile);
    const res = await fetch(`http://localhost:5050/api/students/reports/upload`, {
      method: "POST",
      headers: { Authorization: `Bearer ${token}` },
      body: form,
    });
    const data = await res.json();
    if (res.ok) {
      setReportFile(null);
      loadAll();
    } else setError(data.error);
  };

  return (
    <div className="student-dashboard">
      {/* HEADER */}
      <div className="dashboard-header">
        <h1>Student Dashboard</h1>
        <button className="logout-btn" onClick={handleLogout}>Logout</button>
      </div>

      {/* TABS */}
      <div className="tab-container">
        <button className={tab === "overview" ? "tab active" : "tab"} onClick={() => setTab("overview")}>
          Overview
        </button>
        <button className={tab === "reports-meetings" ? "tab active" : "tab"} onClick={() => setTab("reports-meetings")}>
          Reports & Meetings
        </button>
        <button className={tab === "mentors" ? "tab active" : "tab"} onClick={() => setTab("mentors")}>
          Mentors
        </button>
      </div>

      {error && <p className="error-banner">{error}</p>}

      {/* OVERVIEW TAB */}
      {tab === "overview" && (
        <div className="tab-content">
          <h2 className="welcome-title">Welcome, {profile.studentname}!</h2>
          <div className="profile-card">
            <p><strong>Email:</strong> {profile.Email}</p>
            <p><strong>Semester:</strong> {profile.semester}</p>
            <p><strong>Section:</strong> {profile.section}</p>
            <p><strong>Batch:</strong> {profile.batch}</p>
          </div>
        </div>
      )}

      {/* REPORTS & MEETINGS TAB */}
      {tab === "reports-meetings" && (
        <div className="tab-content grid-2">
          {/* MEETINGS */}
          <div className="info-card">
            <h3>Scheduled Meetings</h3>
            {meetings.length === 0 ? (
              <p className="empty">No upcoming meetings.</p>
            ) : (
              <table className="meetings-table">
                <thead>
                  <tr><th>Day</th><th>Time</th><th>Mentor</th></tr>
                </thead>
                <tbody>
                  {meetings.map(m => (
                    <tr key={m.id}>
                      <td>{m.day}</td>
                      <td>{m.start_time} – {m.end_time}</td>
                      <td>{m.facultyname}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </div>

          {/* REPORTS */}
          <div className="info-card">
            <h3>Progress Reports</h3>
            <form onSubmit={uploadReport} className="upload-form">
              <input type="file" accept=".pdf,.pptx" onChange={e => setReportFile(e.target.files[0])} required />
              <button type="submit">Upload</button>
            </form>
            {reports.length === 0 ? (
              <p className="empty">No reports submitted.</p>
            ) : (
              <ul className="report-list">
                {reports.map(r => (
                  <li key={r.id}>{r.filename} – <strong>{r.status}</strong></li>
                ))}
              </ul>
            )}
          </div>
        </div>
      )}

      {/* MENTORS TAB */}
      {tab === "mentors" && (
        <div className="tab-content">
          <h2 className="section-title">All Mentors</h2>
          <div className="mentors-grid">
            {mentors.map(m => (
              <div key={m.sno} className="mentor-card">
                <h4>{m.facultyname}</h4>
                <p><strong>Specialization:</strong> {m.specialization}</p>
                <p><strong>Email:</strong> {m.Email}</p>
                <button className="request-btn" onClick={() => openProjectModal(m.sno)}>
                  Request Mentor
                </button>
              </div>
            ))}
          </div>

          {/* PROJECT MODAL */}
          {showProjectModal && (
            <div className="modal-overlay" onClick={() => setShowProjectModal(false)}>
              <div className="modal-content" onClick={e => e.stopPropagation()}>
                <h3>Submit Project Idea</h3>
                <form onSubmit={submitProject}>
                  <label>Mentor</label>
                  <select value={selectedMentor} onChange={e => setSelectedMentor(e.target.value)} required>
                    <option value="">-- Select Mentor --</option>
                    {mentors.map(m => (
                      <option key={m.sno} value={m.sno}>{m.facultyname}</option>
                    ))}
                  </select>

                  <label>Title</label>
                  <input value={projTitle} onChange={e => setProjTitle(e.target.value)} required />

                  <label>Domain</label>
                  <input value={projDomain} onChange={e => setProjDomain(e.target.value)} required />

                  <label>Description</label>
                  <textarea value={projDesc} onChange={e => setProjDesc(e.target.value)} required />

                  <div className="modal-actions">
                    <button type="submit">Submit Request</button>
                    <button type="button" onClick={() => setShowProjectModal(false)}>Cancel</button>
                  </div>
                </form>
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default StudentDashboard;
